import{_ as a,c as i,o,ae as t}from"./chunks/framework.Bw7rlmih.js";const h=JSON.parse('{"title":"CP-001: Scope Prefix Model","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/atomic/CP-001-scope-prefix-model.md","filePath":"control-plane/atomic/CP-001-scope-prefix-model.md"}'),l={name:"control-plane/atomic/CP-001-scope-prefix-model.md"};function r(c,e,n,s,d,p){return o(),i("div",null,e[0]||(e[0]=[t('<h1 id="cp-001-scope-prefix-model" tabindex="-1">CP-001: Scope Prefix Model <a class="header-anchor" href="#cp-001-scope-prefix-model" aria-label="Permalink to &quot;CP-001: Scope Prefix Model&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Define logical organization using a single scope string, not hard namespaces.</p><h2 id="inputs-outputs" tabindex="-1">Inputs / Outputs <a class="header-anchor" href="#inputs-outputs" aria-label="Permalink to &quot;Inputs / Outputs&quot;">​</a></h2><ul><li>Input: any API/CLI action requiring target location.</li><li>Output: canonical scope string used across storage, auth, events, and drift.</li></ul><h2 id="public-interfaces" tabindex="-1">Public Interfaces <a class="header-anchor" href="#public-interfaces" aria-label="Permalink to &quot;Public Interfaces&quot;">​</a></h2><ul><li><code>scope</code> field in all write/read APIs.</li><li><code>--scope</code> flag in CLI.</li></ul><h2 id="data-contracts" tabindex="-1">Data Contracts <a class="header-anchor" href="#data-contracts" aria-label="Permalink to &quot;Data Contracts&quot;">​</a></h2><p>Format: <code>team/app/env/service</code>.</p><p>Validation:</p><ul><li>lowercase alnum + <code>-</code> in each segment</li><li>segment count: 3..6</li><li>no empty segments</li></ul><p>Examples:</p><ul><li><code>platform/payments/prod/api</code></li><li><code>core/identity/dev/auth-service</code></li></ul><h2 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h2><ul><li>Scope is case-sensitive canonical lowercase.</li><li>Prefix matching is path-segment aware.</li></ul><h2 id="failure-modes" tabindex="-1">Failure Modes <a class="header-anchor" href="#failure-modes" aria-label="Permalink to &quot;Failure Modes&quot;">​</a></h2><ul><li><code>400 invalid_scope_format</code></li><li><code>403 scope_access_denied</code></li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><ol><li>Invalid scope format is rejected with clear reason.</li><li>Prefix ACLs match only complete segments.</li><li>Same scope string is used in events and audit records.</li></ol><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Tenant isolation by namespace.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>CP-002 authz checks.</li></ul>',23)]))}const m=a(l,[["render",r]]);export{h as __pageData,m as default};
